function toastManager(){return{toasts:[],nextId:1,addToast(e,t,s="",o=5e3){const l=this.nextId++,a={id:l,type:e,title:t,message:s,show:!0};this.toasts.push(a),o>0&&setTimeout(()=>this.removeToast(l),o)},removeToast(e){const t=this.toasts.findIndex(t=>t.id===e);t>-1&&(this.toasts[t].show=!1,setTimeout(()=>{this.toasts.splice(t,1)},300))}}}function tableSelection(){return{selectedAll:!1,selectedRows:[],get selectedCount(){return this.selectedRows.length},get showBulkActions(){return this.selectedCount>0},toggleAll(){this.selectedAll=!this.selectedAll;document.querySelectorAll(".row-checkbox").forEach(e=>{e.checked=this.selectedAll}),this.updateSelection()},updateSelection(){const e=document.querySelectorAll(".row-checkbox");this.selectedAll=Array.from(e).every(e=>e.checked),this.selectedRows=Array.from(e).filter(e=>e.checked).map(e=>e.value)}}}window.showToast=function(e,t,s="",o=5e3){const l=new CustomEvent("show-toast",{detail:{type:e,title:t,message:s,duration:o}});window.dispatchEvent(l)},window.addEventListener("show-toast",e=>{const t=document.querySelector('[x-data*="toastManager"]');t&&t.__x&&t.__x.$data.addToast(e.detail.type,e.detail.title,e.detail.message,e.detail.duration)});